package com.hospital.management.filter;
import com.hospital.management.util.CsrfTokenUtil;import javax.servlet.*;import javax.servlet.annotation.WebFilter;import javax.servlet.http.*;import java.io.IOException;import java.util.Set;
@WebFilter("/*") public class CsrfFilter implements Filter {private static final Set<String> METHODS=Set.of("POST","PUT","PATCH","DELETE");public void doFilter(ServletRequest a,ServletResponse b,FilterChain c)throws IOException,ServletException{HttpServletRequest q=(HttpServletRequest)a;HttpServletResponse r=(HttpServletResponse)b;String path=q.getRequestURI().substring(q.getContextPath().length());if(METHODS.contains(q.getMethod())&&!path.equals("/health/database")&&!CsrfTokenUtil.validate(q.getSession(false),q.getParameter("csrfToken"))){r.sendError(HttpServletResponse.SC_FORBIDDEN);return;}c.doFilter(a,b);}}
